const webhookData = $('Webhook - Gap Scan').first().json;
const body = webhookData.body || webhookData;
const formId = body.form_id;
const dateFrom = body.date_from;
const dateTo = body.date_to;

if (!formId) throw new Error('form_id is required');
if (!dateFrom || !dateTo) throw new Error('date_from and date_to are required');

const buildSectionMap = $('Code - Build Section Map').first().json;
const formConfig = $('Postgres - Get Form Config').first().json;

const data = $getWorkflowStaticData('global');
data.ticket_sections = {};
data.kb_articles = [];
data.section_map = buildSectionMap.section_map || {};
data.section_field_id = buildSectionMap.section_field_id;
data.scan_params = { 
  form_id: formId, 
  form_name: formConfig.form_name || formId, 
  date_from: dateFrom, 
  date_to: dateTo 
};

const q = `ticket_form_id:${formId} created>${dateFrom} created<${dateTo} custom_field_1260824167549:support_`;
const url = `https://kipuhealth.zendesk.com/api/v2/search/export?filter%5Btype%5D=ticket&query=${encodeURIComponent(q)}&page%5Bsize%5D=1000`;

return [{ json: { url } }];

const data = $getWorkflowStaticData('global');
if (!data.ticket_sections) data.ticket_sections = {};

const ARTICLE_FIELD_IDS = [18158428639387, 25171038337691];
const sectionMapNode = $('Code - Build Section Map').first().json;
const sectionFieldId = Number(sectionMapNode.section_field_id);
const sectionMap = sectionMapNode.section_map || {};

const tickets = $json.results || [];

for (const ticket of tickets) {
  const fields = ticket.custom_fields || [];

  const sf = fields.find(f => Number(f.id) === sectionFieldId);
  const sectionValue = sf?.value || 'unknown';
  if (!sectionMap[sectionValue]) continue;

  let articleLinked = null;
  for (const fid of ARTICLE_FIELD_IDS) {
    const f = fields.find(cf => Number(cf.id) === Number(fid));
    if (f && f.value != null && f.value !== '') {
      const v = String(f.value).toLowerCase().trim();
      if (['kcs_linked_yes','kcslinked_yes','yes','true'].includes(v)) { articleLinked = true; break; }
      if (['kcs_linked_no','kcslinked_no','no','false'].includes(v))   { articleLinked = false; break; }
    }
  }
  if (articleLinked === null) {
    const tags = ticket.tags || [];
    if (tags.some(t => ['kcs_linked_yes','kcslinked_yes'].includes(t))) articleLinked = true;
    else if (tags.some(t => ['kcs_linked_no','kcslinked_no'].includes(t))) articleLinked = false;
  }

  if (!data.ticket_sections[sectionValue]) {
    data.ticket_sections[sectionValue] = { total: 0, linked_yes: 0, linked_no: 0, linked_null: 0, tickets: [] };
  }
  data.ticket_sections[sectionValue].total++;
  if (articleLinked === true)       data.ticket_sections[sectionValue].linked_yes++;
  else if (articleLinked === false) data.ticket_sections[sectionValue].linked_no++;
  else                              data.ticket_sections[sectionValue].linked_null++;

  if (data.ticket_sections[sectionValue].tickets.length < 10) {
    const subject = (ticket.subject || '').trim();
    const description = (ticket.description || '').trim().slice(0, 200);
    if (subject) data.ticket_sections[sectionValue].tickets.push({ subject, description });
  }
}

const hasMore = $json.meta?.has_more === true;
const nextUrl = hasMore ? ($json.links?.next || null) : null;
const total = Object.values(data.ticket_sections).reduce((s,v) => s + v.total, 0);
return [{ json: { next_page: nextUrl, sections_tracked: Object.keys(data.ticket_sections).length, total_tickets_processed: total } }];

const data = $getWorkflowStaticData('global');
if (!data.kb_articles) data.kb_articles = [];

const articles = $json.articles || [];
for (const a of articles) {
  if (!a.draft) {
    data.kb_articles.push({
      id: a.id,
      title: a.title,
      section_id: a.section_id,
      updated_at: a.updated_at,
      outdated: a.outdated || false
    });
  }
}

return [{ json: { next_page: $json.next_page || null, articles_collected: data.kb_articles.length } }];

const data = $getWorkflowStaticData('global');
const ticketSections = data.ticket_sections || {};
const kbArticles = data.kb_articles || [];

const sectionMap = $('Code - Build Section Map').first().json.section_map || {};

const webhookData = $('Webhook - Gap Scan').first().json;
const body = webhookData.body || webhookData;
const formConfig = $('Postgres - Get Form Config').first().json;

const scanParams = {
  form_id: body.form_id,
  form_name: formConfig.form_name || body.form_id,
  date_from: body.date_from,
  date_to: body.date_to
};

const stopWords = new Set(['with','from','that','this','have','been','more','than','template','request','feature','and','the','for']);

function findCandidateArticles(topicName) {
  const keywords = topicName.toLowerCase()
    .replace(/[^a-z0-9\s]/g,' ').split(/\s+/)
    .filter(w => w.length > 3 && !stopWords.has(w));
  return kbArticles.filter(a => {
    const t = a.title.toLowerCase();
    return keywords.some(kw => t.includes(kw));
  }).slice(0, 10).map(a => ({ id: a.id, title: a.title, updated_at: a.updated_at, outdated: a.outdated }));
}

const totalTickets = Object.values(ticketSections).reduce((s,v) => s + v.total, 0);

const NON_SUPPORT = new Set([
  'non-support__abandoned_call_emr','emr_non-support__accounting',
  'emr_client_success_manager__csm_emr','emr_hr','emr_implementation',
  'emr_non-support__it','emr_non-support__labs','emr_non-support__legal',
  'non-support__product','emr_sales','emr_non-support__security',
  'emr_non-support__tech_touch','stakeholder_escalations_emr',
  'vm__unable_to_reach_back_','sandbox_request'
]);

const rawSections = Object.entries(ticketSections)
  .filter(([sv]) => sv !== 'unknown' && !NON_SUPPORT.has(sv))
  .map(([sv, counts]) => {
    const topicName = sectionMap[sv] || sv;
    const candidateArticles = findCandidateArticles(topicName);
    const kcsRate = counts.total > 0 ? ((counts.linked_yes + counts.linked_no) / counts.total) * 100 : 0;
    return {
      section_feature: sv,
      topic_name: topicName,
      ticket_count: counts.total,
      pct_of_total: totalTickets > 0 ? Math.round((counts.total / totalTickets) * 1000) / 10 : 0,
      article_linked_yes: counts.linked_yes,
      article_linked_no: counts.linked_no,
      article_linked_null: counts.linked_null,
      kcs_adoption_pct: Math.round(kcsRate * 10) / 10,
      candidate_articles: candidateArticles,
      tickets: counts.tickets || []
    };
  })
  .filter(r => r.ticket_count > 0)
  .sort((a,b) => b.ticket_count - a.ticket_count);

const scanMeta = {
  scan_id: Date.now().toString(),
  scanned_at: new Date().toISOString(),
  date_from: scanParams.date_from,
  date_to: scanParams.date_to,
  form_name: scanParams.form_name,
  total_tickets: totalTickets,
  total_sections: rawSections.length
};

data.llm_results = [];
data.ticket_sections = null;
data.kb_articles = null;

return rawSections.map(s => ({ json: {
  ...s,
  _total_sections: rawSections.length,
  _scan_meta: scanMeta
}}));

const body = $('Webhook - Chat').first().json.body || $('Webhook - Chat').first().json;
const message = body.message || '';
const history = Array.isArray(body.history) ? body.history.slice(-4) : [];

if (!message) throw new Error('message is required');

const scan = $('Postgres - Load Scan Context').first().json;
const sections = scan.sections || [];

const systemPrompt = scan.scan_id
  ? `You are a KB gap analysis assistant for Kipu EMR support operations. Answer questions ONLY from the scan data provided below. Be concise — this is used in live meetings. Do not make up information not present in the data.

SCAN SUMMARY:
- Form: ${scan.form_name}
- Date range: ${scan.date_from} to ${scan.date_to}
- Scanned at: ${scan.scanned_at}
- Total tickets analyzed: ${(scan.total_tickets||0).toLocaleString()}
- Topics tracked: ${scan.total_topics}
- Coverage score: ${scan.coverage_score}%
- True gaps (no article): ${scan.true_gaps}
- Quality gaps (article needs work): ${scan.quality_gaps}
- Discoverability gaps (article unused): ${scan.discoverability_gaps}
- Covered: ${scan.covered}
- High priority topics: ${scan.high_priority}
- Medium priority topics: ${scan.medium_priority}
- Total deflection potential: ${(scan.total_deflection_potential||0).toLocaleString()} tickets

ALL TOPICS (ordered by ticket volume):
${sections.map(s => `- ${s.topic_name}: ${s.ticket_count} tickets | ${s.gap_type} | priority: ${s.priority} | deflection: ${s.deflection_potential} | KCS: ${s.kcs_adoption_pct}%
  Summary: ${s.gap_summary}
  Action: ${s.recommended_action}`).join('\n')}`
  : 'You are a KB gap analysis assistant. No scan data is available. Ask the user to run a gap scan first.';

const historyMessages = history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.content}`).join('\n');
const userPrompt = historyMessages ? `${historyMessages}\nUser: ${message}` : message;

return [{ json: { system_prompt: systemPrompt, user_prompt: userPrompt, original_message: message } }];

const llmOutput = $('Kipu LLM Webhook - Chat').first().json;
const response = llmOutput.output_text || llmOutput.text || llmOutput.response || '';
const usage = llmOutput.usage || { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 };
return [{ json: { response: String(response).trim(), usage } }];

const section = $json;

const ticketSamples = (section.tickets || []).map((t, i) =>
  `${i + 1}. Subject: "${t.subject}"\n   Description: "${t.description}"`
).join('\n');

const systemPrompt = `You are a knowledge base gap analyst for Kipu EMR support. Analyze the support ticket data for one EMR feature and classify the KB gap.

Return ONLY a valid JSON object with exactly these fields — no markdown, no explanation:
{
  "section_feature": string,
  "topic_name": string,
  "ticket_count": number,
  "pct_of_total": number,
  "gap_type": "true_gap" | "discoverability_gap" | "quality_gap" | "covered",
  "gap_summary": string,
  "recommended_articles": [{"id": number, "title": string, "url": string, "relevance": "high"|"medium"|"low"}],
  "recommended_action": string,
  "priority": "HIGH" | "MEDIUM" | "LOW",
  "deflection_potential": number,
  "kcs_adoption_pct": number
}

STRICT RULES — these override your judgment:
1. section_feature: copy the raw field value exactly as given in the input
2. topic_name: copy the human-readable name exactly as given in the input
3. If no candidate articles were provided, gap_type MUST be "true_gap"
4. If kcs_adoption_pct is 0 AND linked_yes is 0, gap_type CANNOT be "covered"
5. "covered" requires articles to exist AND kcs_adoption_pct > 0
6. Priority: HIGH = 100+ tickets, MEDIUM = 30-99, LOW = under 30
7. Base ALL analysis strictly on the data provided — do not infer, assume, or draw on outside knowledge about the software, processes, or industry. If the ticket samples do not provide enough context to make a specific observation, say so plainly.

Gap type definitions:
- true_gap: No relevant KB articles exist — agents have nothing to link
- discoverability_gap: Articles exist but kcs_adoption_pct is 0 — agents are not finding or linking them
- quality_gap: Articles exist AND linked_yes > 0, but tickets keep coming — content needs improvement
- covered: Articles exist AND kcs_adoption_pct > 0 — topic is supported

gap_summary: 2-3 plain English sentences for a live executive meeting. Reference ticket volume, article availability, and what the ticket samples reveal about the actual issue. Do not mention internal field names.
recommended_articles: 1-3 most relevant from candidates only. URL: https://kipuhealth.zendesk.com/hc/en-us/articles/{id}
deflection_potential: 60% of ticket_count for true_gap, 40% for discoverability_gap, 25% for quality_gap, 0 for covered.`;

const userPrompt = `Section: ${section.topic_name} (${section.section_feature})
Tickets: ${section.ticket_count} (${section.pct_of_total}% of total scanned)
KCS Adoption: ${section.kcs_adoption_pct}%
  Linked yes: ${section.article_linked_yes}
  Linked no: ${section.article_linked_no}
  Not recorded: ${section.article_linked_null}

Ticket samples (subject + first 200 chars of description):
${ticketSamples || 'No samples available'}

Candidate KB articles (keyword matched — may include irrelevant results):
${section.candidate_articles.length > 0
  ? section.candidate_articles.map(a => `- [${a.id}] "${a.title}" | updated: ${a.updated_at.slice(0,10)} | outdated: ${a.outdated}`).join('\n')
  : 'None found'}

Return ONLY the JSON object.`;

return { json: {
  system_prompt: systemPrompt,
  prompt: userPrompt,
  section_feature: section.section_feature,
  topic_name: section.topic_name,
  ticket_count: section.ticket_count
}};

const raw = $json.output_text || $json.text || $json.response || '';
const usage = $json.usage || { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 };

const data = $getWorkflowStaticData('global');
if (!data.llm_results) data.llm_results = [];

let parsed;
try {
  const match = String(raw).match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON in response');
  parsed = JSON.parse(match[0]);
} catch(e) {
  parsed = {
    gap_type: 'unknown',
    gap_summary: 'Analysis unavailable.',
    recommended_articles: [],
    recommended_action: 'Manual review required.',
    priority: 'LOW',
    deflection_potential: 0,
    kcs_adoption_pct: 0
  };
}

parsed.section_feature = $('Code - Build Section Prompt').item.json.section_feature;
parsed.topic_name = $('Code - Build Section Prompt').item.json.topic_name;
parsed.ticket_count = $('Code - Build Section Prompt').item.json.ticket_count;
parsed.article_linked_yes = $('Code - Build Coverage Map').item.json.article_linked_yes || 0;
parsed.article_linked_no = $('Code - Build Coverage Map').item.json.article_linked_no || 0;
parsed.article_linked_null = $('Code - Build Coverage Map').item.json.article_linked_null || 0;

data.llm_results.push(parsed);

const totalSections = $('Code - Build Coverage Map').item.json._total_sections || 1;
const isDone = data.llm_results.length >= totalSections;

return { json: { is_done: isDone, usage, section_done: parsed.topic_name, count: data.llm_results.length, total: totalSections, result: parsed } };

const data = $getWorkflowStaticData('global');
const allItems = $('Code - Parse LLM Prompt').all();
const coverageMap = allItems
  .map(item => item.json.result)
  .filter(Boolean)
  .sort((a,b) => (b.ticket_count||0) - (a.ticket_count||0));

coverageMap.forEach(r => r.deflection_potential = Math.round(r.deflection_potential));

const scanMeta = $('Code - Build Coverage Map').first().json._scan_meta || {
  scan_id: Date.now().toString(),
  scanned_at: new Date().toISOString(),
  date_from: null,
  date_to: null,
  form_name: 'Unknown',
  total_tickets: 0
};

const trueGaps = coverageMap.filter(r => r.gap_type === 'true_gap').length;
const qualityGaps = coverageMap.filter(r => r.gap_type === 'quality_gap').length;
const discoverabilityGaps = coverageMap.filter(r => r.gap_type === 'discoverability_gap').length;
const covered = coverageMap.filter(r => r.gap_type === 'covered').length;
const totalDeflection = coverageMap.reduce((s,r) => s + (r.deflection_potential || 0), 0);
const coverageScore = coverageMap.length > 0 ? Math.round((covered / coverageMap.length) * 100) : 0;

data.llm_results = null;

return [{ json: {
  scan_id: scanMeta.scan_id,
  scanned_at: scanMeta.scanned_at,
  date_from: scanMeta.date_from,
  date_to: scanMeta.date_to,
  form_name: scanMeta.form_name,
  total_tickets: scanMeta.total_tickets,
  total_topics: coverageMap.length,
  coverage_score: coverageScore,
  total_deflection_potential: totalDeflection,
  summary: {
    true_gaps: trueGaps,
    quality_gaps: qualityGaps,
    discoverability_gaps: discoverabilityGaps,
    covered,
    high_priority: coverageMap.filter(r => r.priority === 'HIGH').length,
    medium_priority: coverageMap.filter(r => r.priority === 'MEDIUM').length
  },
  coverage_map: coverageMap
}}];

const field = $json.ticket_field;
const options = field.custom_field_options || [];

const sectionMap = {};
options.forEach(opt => {
  sectionMap[opt.value] = opt.name;
});

const data = $getWorkflowStaticData('global');
data.section_map = sectionMap;
data.section_field_id = field.id.toString();

return [{ json: { 
  section_field_id: field.id.toString(),
  section_field_name: field.title,
  total_options: options.length,
  section_map: sectionMap
}}];

const scanData = $('Code - Assemble Final Output').first().json;
const scanId = scanData.scan_id;
const coverageMap = scanData.coverage_map || [];

const esc = s => (s || '').replace(/'/g, "''");

return coverageMap.map(s => ({ json: {
  scan_id: scanId,
  section_feature: esc(s.section_feature),
  topic_name: esc(s.topic_name),
  ticket_count: s.ticket_count,
  pct_of_total: s.pct_of_total,
  gap_type: s.gap_type,
  gap_summary: esc(s.gap_summary),
  recommended_action: esc(s.recommended_action),
  priority: s.priority,
  deflection_potential: s.deflection_potential,
  kcs_adoption_pct: s.kcs_adoption_pct,
  article_linked_yes: s.article_linked_yes || 0,
  article_linked_no: s.article_linked_no || 0,
  article_linked_null: s.article_linked_null || 0,
  recommended_articles: esc(JSON.stringify(s.recommended_articles || []))
}}));
